+      <p className="text-xs font-medium text-neutral-600">{label} (read-only)</p>
+      <p className="rounded-md bg-neutral-100 px-3 py-2 text-sm text-neutral-700">
+        {runs || '—'}
+      </p>
+    </div>
+  );
+}
