+              name="intent"
+              value="publish"
+              disabled={submitting}
+              className="inline-flex min-h-11 cursor-pointer items-center rounded-md bg-neutral-900 px-4 text-sm font-medium text-white hover:bg-neutral-700 disabled:opacity-50"
+            >
+              {submitting ? 'Publishing…' : 'Publish'}
+            </button>
+          </div>
+        </div>
+      </Form>
+    </div>
+  );
