 68	const decodePageId = Schema.decodeUnknownOption(PageId);
 69	
 70	/** A human label for each page (the admin nav + heading). */
 71	const PAGE_LABELS: { readonly [P in PageId]: string } = {
 72	  about: 'About',
 73	  faq: 'FAQ',
 74	  give: 'Give',
 75	  contact: 'Contact',
 76	  volunteer: 'Volunteer',
 77	  archive: 'Archive',
 78	  home: 'Home (evergreen sections)',
 79	};
