 81	type ActionResponse = ActionResult;
 82	
 83	/** Map a `DraftEditor` `IssueError` to the editor's JSON action response. */
 84	const issueResponse = (error: IssueError): Response =>
 85	  Response.json(
 86	    { ok: false, error: error.message, issues: error.issues },
 87	    { status: error.status },
 88	  );
 89	
 90	/** Auth gate shared by the loader + action (404 when admin is disabled). */
 91	const requireAdmin = Effect.fn('admin/pages.requireAdmin')(function* () {
 92	  const { request } = yield* ReactRouterContext;
 93	  const auth = yield* Auth.Service;
 94	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
 95	    Effect.catchTags({
 96	      'Auth.Disabled': () =>
 97	        Effect.fail(new Response('Not Found', { status: 404 })),
 98	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
 99	    }),
100	  );
101	});
102	
103	/** Resolve the `:page` param to a `PageId` or 404 the route. */
104	const requirePageId = Effect.fn('admin/pages.requirePageId')(function* () {
105	  const { params } = yield* ReactRouterContext;
106	  const id = decodePageId(params['page']);
107	  if (Option.isNone(id)) {
108	    return yield* Effect.fail(new Response('Not Found', { status: 404 }));
109	  }
110	  return id.value;
111	});
112	
113	export const loader = routeHandler(function* () {
114	  yield* requireAdmin();
115	  const page = yield* requirePageId();
116	
117	  const editor = yield* DraftEditor.Service;
118	  const env = yield* Env.Service;
119	  const { content, source } = yield* editor.load(pageScope(page));
120	  // Encode the decoded DRAFT page to the JSON the form renders from — the same
121	  // encoded shape `DraftEditor.editDocument` merges the form override onto.
122	  const encode = Schema.encodeUnknownEffect(PAGE_SPECS[page].draftSchema);
123	  const encoded = (yield* encode(content)) as Json;
124	  const bucketConfigured = Option.isSome(env.bucket);
125	
126	  return { page, encoded, source, bucketConfigured };
127	});
128	
129	export const action = routeAction(function* () {
130	  yield* requireAdmin();
131	  const page = yield* requirePageId();
132	  const scope = pageScope(page);
133	
134	  const editor = yield* DraftEditor.Service;
135	  const { request } = yield* ReactRouterContext;
136	  const form = yield* Effect.promise(() => request.formData());
137	  const intent = String(form.get('intent') ?? 'save-draft');
138	
139	  // ---- list op (add / remove / reorder) ------------------------------------
140	  if (intent === 'list-op') {
141	    const ops = collectListOps(form.entries());
142	    if (ops.length === 0) {
143	      return Response.json(
144	        { ok: false, error: 'No list change to apply.', issues: [] },
145	        { status: 400 },
146	      );
147	    }
148	    const applied = yield* editor.applyListOps(scope, ops).pipe(Effect.result);
149	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
150	    return redirect(`/admin/pages/${page}?status=List%20updated.`);
151	  }
152	
153	  if (intent !== 'save-draft' && intent !== 'publish') {
154	    return Response.json(
155	      { ok: false, error: 'Unknown submit intent.', issues: [] },
156	      { status: 400 },
157	    );
158	  }
159	
160	  // ---- save / publish ------------------------------------------------------
161	  // The page form carries only dotted-path fields (no translation god-bag — page
162	  // copy lives in the typed object now), so `assembleOverrides` is the whole
163	  // override; `DraftEditor.editDocument` merges it onto the current page, decodes
164	  // at the page's DRAFT boundary, and stores `…draft.json`.
165	  const override = assembleOverrides(form.entries());
166	  const edited = yield* editor.editDocument(scope, override).pipe(Effect.result);
167	  if (edited._tag === 'Failure') return issueResponse(edited.failure);
168	
169	  if (intent === 'save-draft') {
170	    return redirect(`/admin/pages/${page}?status=Draft%20saved.`);
171	  }
172	
173	  const published = yield* editor.publish(scope).pipe(Effect.result);
174	  if (published._tag === 'Failure') return issueResponse(published.failure);
175	  return redirect(
176	    `/admin/pages/${page}?status=Published.%20Live%20on%20the%20next%20page%20load.`,
177	  );
178	});
