 52	/**
 53	 * The `/admin/content` editor (CMS plan sub-commit C5).
 54	 *
 55	 * It edits the one bilingual `SiteContent` document over three sections —
 56	 * conferences, team, translations — and persists via `Storage`:
 57	 *   - **Save draft** writes `content/site.draft.json` (private to admin);
 58	 *   - **Publish** writes `content/site.json`, removes the draft, and **busts the
 59	 *     `Content` read cache** so the change is live on the next public read with
 60	 *     NO redeploy (D3);
 61	 *   - per-image **Upload** stores the raw bytes under `images/uploads/…` and
 62	 *     rewrites the targeted `…key` field to the new bucket object key (the
 63	 *     resize/WebP/thumbnail pipeline is deferred — CMS plan §"Non-goals").
 64	 *
 65	 * The merge-onto-current-document strategy (`~/lib/content/admin-form`) means the
 66	 * form only carries the fields it renders; every unedited deep field (long bios,
 67	 * `Option` registration windows, image keys) survives, and the merged result is
 68	 * Schema-decoded at the single boundary before it is stored
 69	 * (`boundary-discipline`, `make-impossible-states-unrepresentable`).
 70	 */
 71	
 72	// `encodeDocument` yields the encoded object the React view renders from the
 73	// loader's `DraftEditor.load(siteScope)` result. It encodes the DRAFT shape
 74	// (`DraftSiteContent`): a
 75	// reopened draft may carry a freshly-added list item holding only its `id`
 76	// (ADR 0006), so the view must render partial items. The merge/decode/re-encode/
 77	// store choreography lives in `DraftEditor`; the route only encodes for display.
 78	const encodeDocument = Schema.encodeUnknownEffect(DraftSiteContent);
 79	
 80	type EncodedDocument = typeof DraftSiteContent.Encoded;
 81	
 82	/** Map a `DraftEditor` `IssueError` to the editor's JSON action response. */
 83	const issueResponse = (error: IssueError): Response =>
 84	  Response.json(
 85	    { ok: false, error: error.message, issues: error.issues },
 86	    { status: error.status },
 87	  );
