 89	export const loader = routeHandler(function* () {
 90	  const { request } = yield* ReactRouterContext;
 91	  const auth = yield* Auth.Service;
 92	  // 404 the whole area when disabled; the layout guard already redirected an
 93	  // unauthenticated visitor, but re-checking keeps this route safe on its own.
 94	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
 95	    Effect.catchTags({
 96	      'Auth.Disabled': () =>
 97	        Effect.fail(new Response('Not Found', { status: 404 })),
 98	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
 99	    }),
100	  );
101	
102	  const editor = yield* DraftEditor.Service;
103	  const env = yield* Env.Service;
104	  const { content: document, source } = yield* editor.load(siteScope);
105	  const encoded = yield* encodeDocument(document);
106	
107	  // The bucket is "configured" exactly when `Env.bucket` is present — the single
108	  // source of truth (a bucket-less editor still renders so the admin can preview,
109	  // but saving/publishing would fail, which we warn about up front).
110	  const bucketConfigured = Option.isSome(env.bucket);
111	
112	  return { document: encoded as EncodedDocument, source, bucketConfigured };
113	});
