115	export const action = routeAction(function* () {
116	  const { request } = yield* ReactRouterContext;
117	  const auth = yield* Auth.Service;
118	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
119	    Effect.catchTags({
120	      'Auth.Disabled': () =>
121	        Effect.fail(new Response('Not Found', { status: 404 })),
122	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
123	    }),
124	  );
125	
126	  const editor = yield* DraftEditor.Service;
127	  const storage = yield* Storage.Service;
128	  const form = yield* Effect.promise(() => request.formData());
129	  const intent = String(form.get('intent') ?? 'save-draft');
130	
131	  // ---- image upload --------------------------------------------------------
132	  // The route owns the FormData side: validate the file and store its raw bytes;
133	  // `DraftEditor.applyImageUpload` then rewrites the targeted `…key` field on the
134	  // draft so the new image survives a reload and a later publish.
135	  const uploadTarget = imageUploadTarget(intent);
136	  if (uploadTarget !== null) {
137	    const file = form.get('file');
138	    if (!(file instanceof File) || file.size === 0) {
139	      return Response.json(
140	        { ok: false, error: 'Choose an image before uploading.', issues: [] },
141	        { status: 400 },
142	      );
143	    }
144	    if (!isAcceptedImageType(file.type)) {
145	      return Response.json(
146	        {
147	          ok: false,
148	          error: 'Upload a JPEG, PNG, WebP, GIF, or AVIF image.',
149	          issues: [],
150	        },
151	        { status: 400 },
152	      );
153	    }
154	
155	    const now = yield* Clock.currentTimeMillis;
156	    const key = uploadedImageKey(uploadTarget, file.type, now);
157	    const bytes = new Uint8Array(yield* Effect.promise(() => file.arrayBuffer()));
158	
159	    const putExit = yield* Effect.exit(storage.put(key, bytes, file.type));
160	    if (putExit._tag === 'Failure') {
161	      return Response.json(
162	        {
163	          ok: false,
164	          error:
165	            'Image upload failed — is the bucket configured? ' +
166	            Cause.pretty(putExit.cause),
167	          issues: [],
168	        },
169	        { status: 502 },
170	      );
171	    }
172	
173	    const applied = yield* editor
174	      .applyImageUpload(siteScope, uploadTarget, key)
175	      .pipe(Effect.result);
176	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
177	    return redirect(
178	      `/admin/content?status=${encodeURIComponent(`Image uploaded: ${key}`)}`,
179	    );
180	  }
181	
182	  // ---- list op (add / remove / reorder) ------------------------------------
183	  // A per-list Add / Remove / reorder control submits `list:<path>:<kind>` fields
184	  // (ADR 0006). The route parses them into `ListOp`s; `DraftEditor.applyListOps`
185	  // performs the id-keyed structural edit on the draft and auto-saves it (settled
186	  // #10) so a freshly-added item's id exists server-side before a photo upload /
187	  // field edit targets it. An "Add" appends an item carrying only its id — draft-
188	  // valid, publish-invalid until its bilingual fields are filled (ADR 0006).
189	  if (intent === 'list-op') {
190	    const ops = collectListOps(form.entries());
191	    if (ops.length === 0) {
192	      return Response.json(
193	        { ok: false, error: 'No list change to apply.', issues: [] },
194	        { status: 400 },
195	      );
196	    }
197	    const applied = yield* editor.applyListOps(siteScope, ops).pipe(Effect.result);
198	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
199	    return redirect('/admin/content?status=List%20updated.');
200	  }
201	
202	  if (intent !== 'save-draft' && intent !== 'publish') {
203	    return Response.json(
204	      { ok: false, error: 'Unknown submit intent.', issues: [] },
205	      { status: 400 },
206	    );
207	  }
208	
209	  // ---- save / publish ------------------------------------------------------
210	  // Parse the form into ONE override: dotted-path fields via `assembleOverrides`,
211	  // plus the `t:<locale>:<key>` translation fields folded onto `translations`
212	  // (their keys carry dots, so they can't ride the dotted-path convention).
213	  // `DraftEditor.editDocument` merges it onto the current document, decodes at
214	  // the single boundary, and stores the draft.
215	  const override = deepMerge(assembleOverrides(form.entries()), {
216	    translations: collectTranslations(form.entries()),
217	  } as Json);
218	
219	  const edited = yield* editor
220	    .editDocument(siteScope, override)
221	    .pipe(Effect.result);
222	  if (edited._tag === 'Failure') return issueResponse(edited.failure);
223	
224	  if (intent === 'save-draft') {
225	    return redirect('/admin/content?status=Draft%20saved.');
226	  }
227	
228	  // publish: promote the just-saved draft to the live document, drop the draft,
229	  // and bust the read cache so the change is live on the next public read.
230	  const published = yield* editor.publish(siteScope).pipe(Effect.result);
231	  if (published._tag === 'Failure') return issueResponse(published.failure);
232	  return redirect(
233	    '/admin/content?status=Published.%20Live%20on%20the%20next%20page%20load.',
234	  );
235	});
