221	describe('draft page variants tolerate id-only adds; strict schema blocks publish', () => {
222	  const ID = 'd'.repeat(21);
223	
224	  test('an id-only FAQ item is draft-valid but publish-invalid', () => {
225	    const base = { title: { en: 'FAQ', fr: 'FAQ' }, items: [{ id: ID }] };
