466	export const layer = Layer.effect(
467	  Service,
468	  Effect.gen(function* () {
469	    const storage = yield* Storage.Service;
470	    const content = yield* Content.Service;
471	
472	    /**
473	     * Read + decode the document at `key` through the scope's `fromBucket` codec,
474	     * or `Option.none()` when it is absent / unreadable / malformed (logged,
475	     * never thrown — a bad draft must not break the editor open).
476	     */
477	    const readDocument = (
478	      codec: ScopeCodec,
479	      key: string,
480	    ): Effect.Effect<Option.Option<unknown>> =>
481	      Effect.gen(function* () {
482	        const object = yield* storage.get(key);
483	        const json = yield* Effect.promise(() =>
484	          new Response(object.stream).text(),
485	        );
486	        return Option.some(yield* codec.fromBucket(json));
487	      }).pipe(
488	        Effect.catchCause((cause) =>
489	          Effect.logWarning(`DraftEditor: could not read ${key}`, cause).pipe(
490	            Effect.as(Option.none<unknown>()),
491	          ),
492	        ),
493	      );
494	
495	    const loadInternal = (
496	      scope: ContentScope,
497	    ): Effect.Effect<{ content: unknown; source: LoadedSource }> =>
498	      Effect.gen(function* () {
499	        const codec = resolveScope(scope);
500	        const { draftKey, publishedKey } = codec.keys;
501	        const draft = yield* readDocument(codec, draftKey);
502	        const published = yield* readDocument(codec, publishedKey);
503	
504	        if (Option.isSome(draft)) {
505	          if (Option.isNone(published)) {
506	            return { content: draft.value, source: 'draft' as const };
507	          }
508	          const draftHead = yield* storage
509	            .head(draftKey)
510	            .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
511	          const publishedHead = yield* storage
512	            .head(publishedKey)
513	            .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
514	          const draftIsNewer =
515	            Option.isSome(draftHead) &&
516	            Option.isSome(publishedHead) &&
517	            draftHead.value.lastModified.getTime() >
518	              publishedHead.value.lastModified.getTime();
519	          if (draftIsNewer) {
520	            return { content: draft.value, source: 'draft' as const };
521	          }
522	          return { content: published.value, source: 'published' as const };
523	        }
524	
525	        if (Option.isSome(published)) {
526	          return { content: published.value, source: 'published' as const };
527	        }
528	        return { content: codec.default, source: 'defaults' as const };
529	      });
530	
531	    const load = Effect.fn('DraftEditor.load')(function* <
532	      S extends ContentScope,
533	    >(scope: S) {
534	      return (yield* loadInternal(scope)) as Loaded<S>;
535	    });
536	
537	    /**
538	     * Decode a merged/edited candidate document at the scope's DRAFT boundary,
539	     * rejecting with a 400 `IssueError` carrying its dotted field issues. Shared
540	     * by `editDocument` (form merge), `applyImageUpload` (key rewrite), and
541	     * `applyListOps` (structural edit) — the single draft decode boundary.
542	     */
543	    const decodeOrReject = (
544	      codec: ScopeCodec,
545	      candidate: Json,
546	    ): Effect.Effect<unknown, IssueError> =>
547	      codec.decodeDraft(candidate).pipe(
548	        Effect.mapError(
549	          (error) =>
550	            new IssueError({
551	              message: 'Validation failed — fix the fields below and resubmit.',
552	              issues: issueMessages(error.issue),
553	              status: 400,
554	            }),
555	        ),
556	      );
557	
558	    /**
559	     * Re-encode a decoded DRAFT document to its canonical JSON and store it at
560	     * `draftKey`, rejecting with a 502 `IssueError` on a storage failure.
561	     * Returns the encoded object so callers can hand it back to the view.
562	     */
563	    const storeDraft = (
564	      codec: ScopeCodec,
565	      decoded: unknown,
566	    ): Effect.Effect<Json, IssueError> =>
567	      Effect.gen(function* () {
568	        // A decoded value always re-encodes — a failure here is a bug, not a
569	        // user error, so it dies rather than masquerading as an `IssueError`.
570	        const json = yield* codec.encodeDraftJson(decoded).pipe(Effect.orDie);
571	        yield* storage.put(codec.keys.draftKey, json, 'application/json').pipe(
572	          Effect.mapError(
573	            (cause) =>
574	              new IssueError({
575	                message: `Saving the draft failed — is the bucket configured? ${String(cause)}`,
576	                issues: [],
577	                status: 502,
578	              }),
579	          ),
580	        );
581	        return yield* codec.encodeObject(decoded).pipe(Effect.orDie);
582	      });
583	
584	    /** Encode the scope's current document to its canonical mergeable JSON. */
585	    const encodedCurrent = (
586	      codec: ScopeCodec,
587	      scope: ContentScope,
588	    ): Effect.Effect<Json> =>
589	      Effect.gen(function* () {
590	        const { content: current } = yield* loadInternal(scope);
591	        return yield* codec.encodeObject(current).pipe(Effect.orDie);
592	      });
593	
594	    const editDocument = Effect.fn('DraftEditor.editDocument')(function* <
595	      S extends ContentScope,
596	    >(scope: S, override: Json) {
597	      const codec = resolveScope(scope);
598	      const base = yield* encodedCurrent(codec, scope);
599	      const merged = deepMerge(base, override);
600	      const decoded = yield* decodeOrReject(codec, merged);
601	      return (yield* storeDraft(codec, decoded)) as ScopeEncoded<S>;
602	    });
603	
604	    const applyImageUpload = Effect.fn('DraftEditor.applyImageUpload')(
605	      function* <S extends ContentScope>(
606	        scope: S,
607	        targetPath: string,
608	        key: AssetKey,
609	      ) {
610	        const codec = resolveScope(scope);
611	        const encoded = yield* encodedCurrent(codec, scope);
612	        const next = setAtPath(encoded, targetPath, key);
613	        const decoded = yield* decodeOrReject(codec, next);
614	        return (yield* storeDraft(codec, decoded)) as ScopeEncoded<S>;
615	      },
616	    );
617	
618	    const applyListOps = Effect.fn('DraftEditor.applyListOps')(function* <
619	      S extends ContentScope,
620	    >(scope: S, ops: readonly ListOp[]) {
621	      const codec = resolveScope(scope);
622	      const encoded = yield* encodedCurrent(codec, scope);
623	      // Structural edit by item id, NOT array index: an added item carries only
624	      // its `id` (draft-valid, publish-invalid per ADR 0006), a removed id drops,
625	      // a reorder permutes. The result decodes at the scope's draft boundary.
626	      const edited = applyListEdit(encoded, ops);
627	      const decoded = yield* decodeOrReject(codec, edited);
628	      return (yield* storeDraft(codec, decoded)) as ScopeEncoded<S>;
629	    });
630	
631	    const publish = Effect.fn('DraftEditor.publish')(function* (
632	      scope: ContentScope,
633	    ) {
634	      const codec = resolveScope(scope);
635	      const { draftKey, publishedKey } = codec.keys;
636	      // Promote the just-saved edit. A pending draft is ALWAYS the publish
637	      // source — it is what the admin just edited and saved, so it is published
638	      // directly and never re-reconciled against the published document by
639	      // `lastModified`. This is the behaviour the old inline path had (it wrote
640	      // the freshly-merged document straight to the published key) and is the
641	      // reason `publish` must NOT route through `load`: `load`'s strict
642	      // `draftHead > publishedHead` reconciliation is for *editor-open* only, and
643	      // on a second-granular backend (S3/MinIO) a draft saved and published
644	      // within the same second compares EQUAL — routing publish through `load`
645	      // would silently re-publish the stale document and then delete the edit.
646	      // With no draft, the already-live document is re-published.
647	      const draft = yield* readDocument(codec, draftKey);
648	      const published = yield* readDocument(codec, publishedKey);
649	      const source = Option.isSome(draft)
650	        ? draft.value
651	        : Option.isSome(published)
652	          ? published.value
653	          : codec.default;
654	      // Enforce the STRICT publish invariant before the document goes live:
655	      // re-encode the draft to its JSON shape, then strict-decode it. For the
656	      // site scope a freshly-added (or half-filled) list item that is draft-valid
657	      // but publish-INVALID (an empty required `Text`) is rejected here with a
658	      // 400 `IssueError` carrying the offending field paths — section-skip is for
659	      // *absence* (an empty list), never a tolerance for half-filled content
660	      // (ADR 0006, CONTEXT §Section skip). Only after this gate passes does the
661	      // published object get written.
662	      const draftJson = yield* codec.encodeDraftJson(source).pipe(Effect.orDie);
663	      const strict = yield* parseJson(draftJson).pipe(
664	        Effect.flatMap(codec.decodePublish),
665	        Effect.mapError(
666	          (error) =>
667	            new IssueError({
668	              message:
669	                'Cannot publish — finish the fields below (added or empty items must be complete) and resubmit.',
670	              issues: issueMessages(error.issue),
671	              status: 400,
672	            }),
673	        ),
674	      );
675	      const json = yield* codec.encodePublishJson(strict).pipe(Effect.orDie);
676	      yield* storage.put(publishedKey, json, 'application/json').pipe(
677	        Effect.mapError(
678	          (cause) =>
679	            new IssueError({
680	              message: `Publishing failed — is the bucket configured? ${String(cause)}`,
681	              issues: [],
682	              status: 502,
683	            }),
684	        ),
685	      );
686	      // Best-effort cleanup so the bucket stays tidy. Correctness does NOT
687	      // depend on it: the published document above already carries the promoted
688	      // draft, so a leftover draft (from a failed delete) only governs what the
689	      // *editor* reopens, where `load`'s strictly-newer reconciliation keeps it
690	      // from reopening as stale content. Hence it must not fail the publish —
691	      // the live document is already written.
692	      yield* storage.delete(draftKey).pipe(Effect.ignore);
693	      // Bust ONLY this scope's published read cache (ADR 0008): publishing a page
694	      // makes that page live on the next read without busting any other page,
695	      // form, or the conference (`site`) cache.
696	      yield* content.bust(bustTargetOf(scope));
697	    });
698	
699	    return Service.of({
700	      load,
701	      editDocument,
702	      applyImageUpload,
703	      applyListOps,
704	      publish,
705	    });
706	  }),
707	);

